+fn valid_issue_id(raw: &str) -> String {
+    let lower: String = raw
+        .chars()
+        .map(|c| c.to_ascii_lowercase())
+        .filter(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || *c == '-')
+        .collect();
+    let trimmed = lower.trim_matches('-');
+    if trimmed.is_empty() || !trimmed.contains('-') {
+        "bd-fuzz".to_string()
+    } else {
+        trimmed.to_string()
+    }
+}
